import anthropic

client = anthropic.Anthropic()


def evaluate_instruction_following(instruction: str, constraints: dict) -> dict:
    """
    Test whether a model follows specific instruction constraints.
    `constraints` maps constraint name → checker function.
    """
    response = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=512,
        messages=[{"role": "user", "content": instruction}],
    )
    text = response.content[0].text

    results = {}
    for name, checker in constraints.items():
        results[name] = checker(text)
    return {"response": text, "constraints": results}


# Example 1: format constraint
result = evaluate_instruction_following(
    instruction="List the top 3 programming languages in 2024. Use a numbered list only.",
    constraints={
        "is_numbered_list": lambda t: all(
            any(line.strip().startswith(f"{i}.") for line in t.splitlines())
            for i in range(1, 4)
        ),
        "has_exactly_3_items": lambda t: sum(
            1 for line in t.splitlines() if line.strip()[:2] in ["1.", "2.", "3."]
        ) == 3,
    }
)
print(result["constraints"])  # {'is_numbered_list': True, 'has_exactly_3_items': True}

# Example 2: length constraint
result2 = evaluate_instruction_following(
    instruction="Explain what a neural network is. Your answer must be exactly one sentence.",
    constraints={
        "single_sentence": lambda t: t.count(".") <= 2 and len(t.split()) <= 40,
    }
)
print(result2["constraints"])  # {'single_sentence': True}
